const i=[{id:"work_report",name:"工作汇报",icon:"💼",desc:"优化日常工作总结与汇报",color:"#FF8C42",questions:["请用PREP框架汇报你本周的项目进度","假设你在月会上向领导汇报Q3业绩，请开始","用STAR框架描述一个你成功解决的工作难题","请用3分钟时间汇报你的年度工作计划","向客户汇报项目延期原因和改进方案"]},{id:"interview",name:"面试应答",icon:"🎯",desc:"应对各种面试场景",color:"#4A90E2",questions:["请做一个1分钟的自我介绍","你认为你最大的优点和缺点是什么？","请描述一次你成功解决团队冲突的经历","你为什么选择我们公司？","如果遇到不熟悉的面试问题，你会怎么回答？"]},{id:"impromptu",name:"即兴发言",icon:"🎤",desc:"锻炼临场表达能力",color:"#E24A4A",questions:['请用1分钟谈谈你对"终身学习"的理解',"即兴演讲：科技改变生活","如果给你1分钟竞选班长，你会说什么？","谈谈你最近读到的一本好书","如果你中了彩票，你会怎么花？"]},{id:"business",name:"商务谈判",icon:"🤝",desc:"提升商务沟通说服力",color:"#9B59B6",questions:["向客户推销你的产品，争取签下合作","面对客户的压价，如何谈判争取更好的条件","请说服团队采用新的工作流程","与合作方讨论合作条款和分成比例","在商务宴请中做一次简短的祝酒词"]},{id:"social",name:"社交破冰",icon:"😊",desc:"轻松融入社交场合",color:"#2ECC71",questions:["在聚会上向新朋友做自我介绍","如何优雅地加入一群人的谈话","在行业会议上认识一位同行，你会说什么","在晚宴上被要求简单发言","在朋友生日聚会上准备一段祝福词"]},{id:"public_speech",name:"公开演讲",icon:"🎪",desc:"掌握大型演讲技巧",color:"#F39C12",questions:["做一个5分钟的TED风格演讲：我的人生信念","在公司年会上发表获奖感言","在毕业典礼上代表毕业生发言","做一次关于AI未来的公开演讲","在创业路演中向投资人介绍你的项目"]}],t=[{id:"logic_prep",name:"PREP框架",icon:"📐",desc:"Point→Reason→Example→Point 结构化表达",color:"#FF8C42",exercises:[{title:"用PREP表达你的观点",prompt:"你认为远程办公利大于弊吗？请用PREP框架回答"},{title:"工作汇报PREP",prompt:"请用PREP框架向领导汇报你的项目进展"},{title:"产品推荐PREP",prompt:"向同事推荐一款你最近使用的APP，用PREP框架"}]},{id:"logic_scqa",name:"SCQA框架",icon:"🔍",desc:"Situation→Complication→Question→Answer",color:"#4A90E2",exercises:[{title:"方案汇报SCQA",prompt:"用SCQA框架提出一个改进团队效率的方案"},{title:"问题分析SCQA",prompt:"用SCQA分析当前工作中最大的痛点"},{title:"项目立项SCQA",prompt:"用SCQA框架做一个新项目立项的简要陈述"}]},{id:"logic_star",name:"STAR框架",icon:"🌟",desc:"Situation→Task→Action→Result",color:"#9B59B6",exercises:[{title:"面试经历分享",prompt:"用STAR框架描述一次你成功解决问题的经历"},{title:"项目复盘STAR",prompt:"用STAR框架复盘一个你参与的项目"},{title:"个人成就STAR",prompt:"用STAR框架讲述你的一个职业成就"}]},{id:"filler_control",name:"填充词控制",icon:"🧹",desc:'减少"嗯""啊""然后"等填充词',color:"#E74C3C",exercises:[{title:"无填充自我介绍",prompt:"做一次30秒的自我介绍，注意不要使用填充词"},{title:"流畅观点表达",prompt:"谈谈你对AI发展的看法，尽量不用填充词"},{title:"连续表达挑战",prompt:"连续说1分钟的话，注意语言的连贯性"}]},{id:"tone_control",name:"语音语调",icon:"🎵",desc:"掌握声音的抑扬顿挫",color:"#3498DB",exercises:[{title:"情感朗读",prompt:"用三种不同情感朗读同一段文字：高兴、严肃、温柔"},{title:"重点强调",prompt:"用不同的语调强调句子中的关键词"},{title:"故事讲述",prompt:"讲述一个有趣的故事，注意语调的变化"}]}],e=[{id:1,topic:"AI会取代人类吗？",timeLimit:120,difficulty:1},{id:2,topic:"什么是成功的秘诀？",timeLimit:90,difficulty:1},{id:3,topic:"如果你可以穿越时空，你会去哪里？",timeLimit:120,difficulty:2},{id:4,topic:"远程办公vs办公室办公，你选哪个？",timeLimit:120,difficulty:2},{id:5,topic:"描述你理想中的工作",timeLimit:90,difficulty:1},{id:6,topic:"你认为什么是最重要的人生品质？",timeLimit:120,difficulty:3},{id:7,topic:"如果给你100万，你会怎么花？",timeLimit:90,difficulty:1},{id:8,topic:'谈谈你对"内卷"的看法',timeLimit:120,difficulty:3},{id:9,topic:"如果你可以拥有一种超能力，你会选什么？",timeLimit:90,difficulty:2},{id:10,topic:"描述一次让你感动的经历",timeLimit:120,difficulty:2},{id:11,topic:"你认为读书有用吗？",timeLimit:120,difficulty:2},{id:12,topic:"如果你是CEO，你会做什么改变？",timeLimit:150,difficulty:3},{id:13,topic:"社交媒体对社会的影响",timeLimit:120,difficulty:3},{id:14,topic:'你如何看待"躺平"文化？',timeLimit:120,difficulty:3},{id:15,topic:"描述你最近学会的一项新技能",timeLimit:90,difficulty:1}],o=[{id:1,title:"PREP表达法",content:"结论→理由→例子→重申结论\n适用于：观点表达、工作汇报\n技巧：先说结论，让人第一时间抓住重点"},{id:2,title:"SCQA框架",content:"情境→冲突→问题→答案\n适用于：方案汇报、说服沟通\n技巧：先用共同认可的情境拉近距离"},{id:3,title:"STAR法则",content:"情境→任务→行动→结果\n适用于：面试、案例分享\n技巧：重点描述你的具体行动"},{id:4,title:"停顿的艺术",content:"有意义的停顿可以：\n• 强调重要观点\n• 给听众消化时间\n• 展示自信\n技巧：说完关键点后停顿2秒"},{id:5,title:"避免填充词",content:"常见的填充词：嗯、啊、然后、就是\n替代方法：用短暂的沉默代替\n技巧：录音回听，统计填充词次数"},{id:6,title:"目光接触",content:"演讲时与听众保持目光接触：\n• 每次注视2-3秒\n• 覆盖左右中不同区域\n• 与个别听众产生连接\n技巧：找几个友好的面孔作为锚点"},{id:7,title:"故事力",content:"好的故事结构：\n• 设定场景（背景）\n• 提出挑战（冲突）\n• 采取行动（解决）\n• 展示结果（教训）\n技巧：加入细节让故事更生动"},{id:8,title:"声音变化",content:"单调的声音让人昏昏欲睡\n• 音量：重点处加大音量\n• 语速：关键信息放慢\n• 音调：疑问上扬，陈述下降\n技巧：录音对比，找出变化空间"}];export{e as C,o as D,i as S,t as a};
